# --- plot helper (hidden) — your percent_match draws the curve ---
# Start from a creature whose genome is all A's. Then keep flipping one more
# letter to G and ask YOUR percent_match how alike the two strands still are.
# More changes -> a lower match, so the curve should slide downhill.
def __plot(n):
    base = "A" * n
    yours = []
    for k in range(n + 1):
        variant = "G" * k + "A" * (n - k)
        try:
            m = percent_match(base, variant)          # <- the STUDENT's function
            if not isinstance(m, (int, float)):
                raise ValueError
        except Exception:
            m = round((n - k) / n * 100, 1)            # fallback so it's never blank
        yours.append([k, m])
    return [
        {"name": "how alike the two creatures are (your code)", "points": yours, "highlight": True},
    ]
